SELECT year, industry, AVG(men_20_over) AS average_employment_rate
FROM employment_statistics
GROUP BY year, industry;

SELECT ag.age_group_description, er.employment_rate, er.unemployment_rate
FROM age_groups ag
INNER JOIN employment_rates er ON ag.age_group_id = er.age_group_id;

SELECT DISTINCT region
FROM employment_statistics
WHERE month = 'Aug-00' AND total > 50;

SELECT E.month, E.industry, ER.employment_rate
FROM employment_statistics E
JOIN employment_rates ER ON E.stat_id = ER.stat_id;

SELECT total, men_20_over, women_20_over, age_16_19, white, black_or_african_american, asian, hispanic_or_latino
FROM employment_statistics
WHERE stat_id = 1;
